# Milestone roadmap: generating a structured timeline
# Produces a JSON roadmap artifact for stakeholder review

import json
from datetime import date, timedelta

def build_roadmap(start_date: date, phases: list) -> dict:
    roadmap = {"generated": str(start_date), "phases": []}
    current = start_date
    for phase in phases:
        months = phase["duration_months"]
        end = current + timedelta(days=30 * months)
        milestones = []
        for m in phase["milestones"]:
            offset_days = int(30 * months * m["at_pct"])
            milestones.append({
                "name": m["name"],
                "target_date": str(current + timedelta(days=offset_days)),
                "owner": m["owner"],
                "success_metric": m["metric"]
            })
        roadmap["phases"].append({
            "name": phase["name"],
            "start": str(current),
            "end": str(end),
            "milestones": milestones
        })
        current = end
    return roadmap

phases = [
    {
        "name": "Phase 1 - Foundation",
        "duration_months": 6,
        "milestones": [
            {"name": "CoE stood up", "at_pct": 0.2, "owner": "CDO", "metric": "Charter signed"},
            {"name": "First pilot live", "at_pct": 0.6, "owner": "CoE Lead", "metric": ">=1 prod use case"},
            {"name": "Phase 1 gate review", "at_pct": 1.0, "owner": "Steering", "metric": "Gate pass/fail"}
        ]
    },
    {
        "name": "Phase 2 - Scale",
        "duration_months": 12,
        "milestones": [
            {"name": "10 use cases", "at_pct": 0.5, "owner": "Portfolio Lead", "metric": "10 in production"},
            {"name": "ROI validated", "at_pct": 0.8, "owner": "Finance", "metric": ">=1 case ROI proven"},
            {"name": "Phase 2 gate review", "at_pct": 1.0, "owner": "Steering", "metric": "Gate pass/fail"}
        ]
    }
]

roadmap = build_roadmap(date(2025, 1, 1), phases)
print(json.dumps(roadmap, indent=2))
